import type {
  Dispatch,
  MutableRefObject,
  SetStateAction,
  WheelEvent,
  FocusEvent,
} from 'react';

import type { StylingProps } from '../../../../core/types/styling-props.js';
import type { MappedObject } from '../../types/helpers/mapped-object.js';
import type {
  DragEndProps,
  DragMoveProps,
  DragStartProps,
  PointerEventModifiers,
  PointerEventPosition,
  RelativeAbsolutePosition,
} from '../../types/pointer-events.js';

/**
 * @internal
 */
export type InteractionMode = 'explore' | 'pan' | 'zoom';

export const INTERACTION_MODE = Object.freeze<MappedObject<InteractionMode>>({
  Explore: 'explore',
  Pan: 'pan',
  Zoom: 'zoom',
});

/**
 * @internal
 */
export type InteractionTriggers = 'pointer' | 'keyboard';

/**
 * @internal
 */
export type KeyboardOnlyInteractionTriggers = Omit<
  InteractionTriggers,
  'pointer'
>;

/**
 * @internal
 */
export type ZoomBehavior = 'zoom-x' | 'zoom-in' | 'zoom-out';

/**
 * @internal
 */
export interface InteractionsOverlayProps extends StylingProps {
  /**
   * Defines current interaction mode
   */
  mode: InteractionMode;
  /**
   * Defines whether the chart has a pinned point
   */
  pinned: boolean;
  /**
   * Defines the current selection area. Can be undefined
   */
  selectionArea?: [RelativeAbsolutePosition, RelativeAbsolutePosition];
  /**
   * The container width
   */
  width: number;
  /**
   * The container height
   */
  height: number;
  /**
   * Whether zoom mode is disabled
   */
  isZoomXDisabled?: boolean;
  /**
   * Whether zoom in/out is disabled
   */
  isZoomDisabled?: boolean;
  /**
   * Whether pan is disabled
   */
  isPanDisabled?: boolean;
  /**
   * Detects if current interaction mode changed. Can be triggered by keyboard
   * @param event - The interaction event, contains:
   * - mode: the new interaction mode
   * - keyboard: whether the mode should be accessible by keyboard
   */
  onModeChange?: (event: { mode: InteractionMode; keyboard: boolean }) => void;
  /**
   * Detects if overlay is focused. Can be triggered by keyboard
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard
   */
  onFocus?: (event?: FocusEvent) => void;
  /**
   * Detects if overlay is hovered. Can be triggered by the mouse
   * @param event - The interaction event, contains:
   * - triggeredBy: pointer (mouse/touch)
   * - position: relative and absolute position of the start of the interaction
   */
  onHover?: (event: {
    triggeredBy: InteractionTriggers;
    position: RelativeAbsolutePosition;
  }) => void;
  /**
   * Detects if overlay is blurred or left by mouse. Can be triggered by keyboard or mouse
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   */
  onLeave?: (event: { triggeredBy: InteractionTriggers }) => void;
  /**
   * Detects pan interaction start. Can be triggered by keyboard or pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   */
  onPanStart?: (event: { triggeredBy: InteractionTriggers }) => void;
  /**
   * Detects pan interaction change. Can be triggered by keyboard or pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   * - delta: distance in pixels of the desired pan change. It can be positive (pan to right) or negative (pan to left)
   */
  onPanChange?: (event: {
    triggeredBy: InteractionTriggers;
    delta: number;
  }) => void;
  /**
   * Detects pan interaction end. Can be triggered by keyboard or pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   */
  onPanEnd?: (event: { triggeredBy: InteractionTriggers }) => void;
  /**
   * Detects pin interaction. Can be triggered by pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   * - position: relative and absolute position of the start of the interaction
   * - pin: whether is action of pin or unpin
   */
  onTogglePin?: (event: {
    triggeredBy: InteractionTriggers;
    position: RelativeAbsolutePosition | undefined;
    pin: boolean;
  }) => void;
  /**
   * Detects reset interaction. Can be triggered by keyboard, pointer (mouse/touch) or resize
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard, pointer (mouse/touch)
   * - mousePosition: the mouse position, if in bounds
   */
  onReset?: (event: {
    triggeredBy: InteractionTriggers;
    mousePosition?: RelativeAbsolutePosition;
  }) => void;
  /**
   * Detects select interaction start. Can be triggered by keyboard or pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   * - position: start position of the selection area
   */
  onSelectStart?: (event: {
    triggeredBy: InteractionTriggers;
    position: RelativeAbsolutePosition;
  }) => void;
  /**
   * Detects select interaction change. Can be triggered by keyboard or pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   * - start: start position of the selection area
   * - end: end position of the selection area
   */
  onSelectChange?: (event: {
    triggeredBy: InteractionTriggers;
    start: RelativeAbsolutePosition;
    end: RelativeAbsolutePosition;
    mode: 'zoom' | 'explore';
  }) => void;
  /**
   * Detects select interaction end. Can be triggered by keyboard or pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   * - start: start position of the selection area
   * - end: end position of the selection area
   * or:
   * - cancelled: whether the interaction was cancelled
   */
  onSelectEnd?: (
    event:
      | {
          triggeredBy: InteractionTriggers;
          start: RelativeAbsolutePosition;
          end: RelativeAbsolutePosition;
        }
      | { cancelled: true },
  ) => void;
  /**
   * Detects zoom interaction start. Can be triggered by keyboard or pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   */
  onZoomStart?: (event: { triggeredBy: InteractionTriggers }) => void;
  /**
   * Detects zoom interaction change. Can be triggered by keyboard or pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   * - deltaStart: distance in pixels of the start side of the desired zoom change. Can be positive (zoom in) and negative (zoom out)
   * - deltaEnd: distance in pixels for the start side of the desired zoom change. Can be positive (zoom out) and negative (zoom in)
   */
  onZoomChange?: (event: {
    triggeredBy: InteractionTriggers;
    deltaStart: number;
    deltaEnd: number;
    behavior: ZoomBehavior;
  }) => void;
  /**
   * Detects zoom interaction end. Can be triggered by keyboard or pointer (mouse/touch)
   * @param event - The interaction event, contains:
   * - triggeredBy: keyboard or pointer (mouse/touch)
   */
  onZoomEnd?: (event: { triggeredBy: InteractionTriggers }) => void;
}

export const isSelectCancelled = (
  event:
    | {
        triggeredBy: InteractionTriggers;
        start: RelativeAbsolutePosition;
        end: RelativeAbsolutePosition;
      }
    | { cancelled: true },
): event is { cancelled: true } => 'cancelled' in event && event.cancelled;

/**
 * @internal
 */
export type OverlappingInteractionsProps = Pick<
  InteractionsOverlayProps,
  | 'pinned'
  | 'selectionArea'
  | 'onSelectEnd'
  | 'onHover'
  | 'onTogglePin'
  | 'height'
  | 'onReset'
  | 'width'
  | 'onZoomChange'
  | 'onPanStart'
  | 'onPanChange'
  | 'onPanEnd'
  | 'onModeChange'
> & {
  eventCancelled: MutableRefObject<boolean>;
  setCursorMode: Dispatch<SetStateAction<InteractionMode | 'zoomOut'>>;
  lastMousePositionRef: MutableRefObject<RelativeAbsolutePosition | undefined>;
  panDeltaRef: MutableRefObject<number | undefined>;
};

/**
 * @internal
 */
export type exploreInteractions = OverlappingInteractionsProps &
  Pick<
    InteractionsOverlayProps,
    'onModeChange' | 'onSelectChange' | 'onSelectStart' | 'isZoomXDisabled'
  >;

/**
 * @internal
 */
export type zoomInteractions = OverlappingInteractionsProps &
  Pick<InteractionsOverlayProps, 'onSelectChange' | 'onSelectStart'> & {
    cursorMode: 'zoomOut' | InteractionMode;
  };

/**
 * @internal
 */
export type panInteractions = OverlappingInteractionsProps & {
  cursorMode: 'zoomOut' | InteractionMode;
};

/**
 * @internal
 */
export type InteractionsHandlers = {
  onMouseHover: (event: PointerEventPosition & PointerEventModifiers) => void;
  onMouseClickOrTap: (
    event: PointerEventPosition & PointerEventModifiers,
  ) => void;
  onDragStart: (event: DragStartProps & PointerEventModifiers) => void;
  onDragMove: (event: DragMoveProps & PointerEventModifiers) => void;
  onDragEnd: (event: DragEndProps & PointerEventModifiers) => void;
  onDoubleClickOrTap: (triggeredBy: InteractionTriggers) => void;
  onWheel: (event: WheelEvent) => void;
  onKeyEscape: () => void;
  onKeyEnter: () => void;
  onKeyRight: (shiftKey: boolean) => void;
  onKeyLeft: (shiftKey: boolean) => void;
  onKeyUp: (isTemporaryZoomMode: boolean) => void;
  onKeyDown: (isTemporaryZoomMode: boolean) => void;
  onDragStartWithMiddleButton: () => void;
  onDragMoveWithMiddleButton: (
    event: DragMoveProps & PointerEventModifiers,
  ) => void;
  onDragEndWithMiddleButton: (
    event: DragEndProps & PointerEventModifiers,
  ) => void;
};

/**
 * @internal
 */
export type Interactions = {
  explore: InteractionsHandlers;
  zoom: InteractionsHandlers;
  pan: InteractionsHandlers;
};
